INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('pm_equipotential_shells_must_be_config_driven_with_v_labels', 'Equipotential shells must read explicit {radius, v_label} from config (1/r-physical, bunched near +Q) with a per-shell V label — the hardcoded even radius = 1.0 + i*1.2 with no labels cannot teach scalar level-sets', 'MAJOR', 'peter_parker:renderer_primitives', 'buildEquipotentialSurfaces hardcoded N evenly-spaced shells (radius = 1.0 + i*1.2) with no V labels, so it could not render the four hero shells (V=9,6,4.5,3 at r=1.0,1.5,2.0,3.0) that are 1/r-physical (r_i = demo_v_per_nc*Q/V_i, bunched near +Q). Without per-shell V numbers the shells cannot read as scalar level-sets (the PRIMARY aha).', 'When config.equipotential.shells = [{radius, v_label}] is present, render a shell at each explicit radius + a V-value label sprite on each (label_each_shell !== false), hidden until the per-state reveal fades them in. ABSENT ⇒ exact legacy even-spacing behaviour (existing point_charge / gauss concepts untouched). Every number is data; the engine never hardcodes the concept values.', 'manual', 'Open STATE_6/STATE_7 of electric_potential_meaning: the cyan shells must sit at the config radii (bunched near +Q, NOT evenly spaced) and each must carry its V number (V=9 innermost … V=3 outermost). Remove the shells block from another point_charge config and confirm the legacy even shells / no-shells behaviour is unchanged.', 'FIXED', ARRAY['electric_potential_meaning'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_electric_potential_meaning_build', 'incident'),
('pm_work_tally_holds_end_value_never_resets_to_zero', 'The route work tally + W/q invariant + V=W/q callout + U badge must HOLD their revealed value (path1 W=6, path2 W=6, q→2q W=12, W/q=6, V=6, U=6) — never fade/snap back to 0 after the animation', 'MAJOR', 'peter_parker:renderer_primitives', 'A one-shot animated readout (the climbing work tally, the draining energy badge, the written V=W/q) that resets to 0 or fades out after its animation completes destroys the teaching payload — the student sees a blank where the result should persist (the field3d_oneshot_element_vanishes_after_animation scar applied to potential).', 'updatePotentialMeaningFrame clamps the route fraction to 1 and holds the final tally text; the energy badge writes "U" and HOLDS at end pose; the V=W/q callout + V value + W/q readout stay opaque once written. Both STATE_2 routes land on the SAME tally (path-independence); STATE_4 doubles the tally (q→2q) while W/q holds (the divide-out-q lesson). Pure state clock (Rule 26).', 'manual', 'Watch STATE_2 to completion: both tallies read W=6 and STAY. Watch STATE_3 release: the badge drains 6→0 then writes "U = stored energy" and STAYS. Watch STATE_4: tally 6→12 while W/q holds 6, then V=W/q + V=6 write in and STAY visible — none fades to 0.', 'FIXED', ARRAY['electric_potential_meaning'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_electric_potential_meaning_build', 'incident'),
('pm_q_grow_is_only_allowed_size_change_rule29', 'The q→2q grow is the ONLY size change in the potential arc (a real physical magnitude doubling, like tauThrob); every other emphasis is brightness, never size (Rule 29)', 'MODERATE', 'peter_parker:renderer_primitives', 'Rule 29 bans zoom/bulge emphasis. The potential arc has one legitimate size change — the scripted q→2q doubling in STATE_4 (a genuine magnitude change that doubles the work) — which must read as a real grow, while NO shell / arrow / charge ever bulges for emphasis.', 'Only the STATE_4 doubling scales the test-charge mesh (1 → 1.26, cube-root of 2 so VOLUME ~doubles); the grow is gated on doubling_at_ms and resets to scale 1 on every other state entry (Rule 26). No other element changes size for emphasis. Shell highlight in STATE_7 brightens opacity, never scales.', 'manual', 'STATE_4 only: the amber +q visibly grows when the narration says "twice as big" (and the tally doubles with it). Every other state: nothing zooms/bulges; the STATE_7 shell-under-charge highlight is a brightness change, not a size change.', 'FIXED', ARRAY['electric_potential_meaning'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_electric_potential_meaning_build', 'incident'),
('pm_devstatemeta_potential_block_registered_same_change', 'electric_potential_meaning per-state `potential` keys registered in deriveStateMeta in the SAME change (else THE EYE mis-classifies every state at the 1500ms default + false-fails STATE_2/3 motion + STATE_7 interactive)', 'MAJOR', 'peter_parker:renderer_primitives', 'A new field_3d teaching arc whose per-state `potential` keys (animate_route, route_at_ms, release_at_ms, doubling_at_ms, v_callout_at_ms, reference_at_ms, delta_v_at_ms, shells_at_ms, e_arrow_at_ms, draggable_test_charge) are not recognised by deriveStateMeta classifies at the 1500ms default → D7/D1p false-fail (the field3d_scenario_missing_devstatemeta_recognition scar).', 'The `potential` block ships in deriveStateMeta in the SAME change: deriveMotionExpectations declares STATE_2 (animate_route) + STATE_3 (release_at_ms) as MOTION; maxRevealForField3dState pins past every reveal beat; deriveHoldExpectations marks STATE_7 (draggable_test_charge) interactive and the reveal states reveal_hold. Guided reveal states must classify reveal_hold (maxReveal > 1500ms); STATE_7 interactive; STATE_2/3 keep the strict motion gate.', 'manual', 'Run visual:eyes on electric_potential_meaning; STATE_2/STATE_3 must declare motion, STATE_4/5/6 must classify reveal_hold (maxReveal > 1500ms), STATE_7 must classify interactive — none at the bare 1500ms default.', 'FIXED', ARRAY['electric_potential_meaning'], ARRAY['src/lib/renderers/field_3d_renderer.ts', 'src/lib/validators/visual/deriveStateMeta.ts'], 'session_2026-06-26_electric_potential_meaning_build', 'incident')
